// Lifetime simulation: applies each job at age 22, runs monthlyTick until death or 90,
// auto-buys real estate / side hustles when affordable, reports aggregate stats per job.
// Usage: node lifetime-sim.js <sector|all> [livesPerJob=3]
const { chromium } = require('playwright');
const sector = process.argv[2] || 'all';
const lives = parseInt(process.argv[3] || '3', 10);

(async () => {
  const b = await chromium.launch({ headless: true });
  const ctx = await b.newContext({ viewport: { width: 1280, height: 800 } });
  const p = await ctx.newPage();
  p.setDefaultTimeout(90000);
  await p.goto('http://localhost:3000/bitlife-finance.html', { waitUntil: 'domcontentloaded' });
  await p.evaluate(() => { try { localStorage.removeItem('finlife_save'); } catch(e){} });
  await p.reload({ waitUntil: 'domcontentloaded' });
  await p.waitForSelector('#screen-new.active', { timeout: 5000 });
  await p.fill('#inp-name', 'LifeSim');
  await p.click('#btn-start');
  await p.waitForSelector('#screen-game.active', { timeout: 5000 });

  const results = await p.evaluate(({ sector, lives }) => {
    // Stub DOM-touching helpers so monthlyTick can run headless
    window.logEvent = () => {};
    window.showToast = () => {};
    window.updateUI = () => {};
    window.showGameOver = () => {};
    window.renderInbox = () => {};
    window.processNextEvent = () => {};

    const jobs = (sector === 'all') ? ALL_JOBS.slice() : ALL_JOBS.filter(j => j.sector === sector);

    function freshChar() {
      // Mimic newChar() / fresh state from this game's structure
      return {
        name:'Sim', age:22, monthAge:22*12, alive:true,
        education:'doctoral', inSchool:false, schoolType:null, schoolMonthsLeft:0, schoolCostMonthly:0,
        smarts:75, health:75, happiness:75, looks:60, performance:70,
        employed:false, jobId:null, jobTitle:null, jobSector:null, salary:0, sportsTeam:null,
        sideHustleIncome:0,
        checking:5000, savings:0, highYield:0, debt:0,
        bankId:null,
        retired:false, lifestyle:'normal',
        bossName:'Test', bossMorale:65, yearsAtJob:0, monthsAtJob:0, careerTierId:'tier1',
        spouseName:null, kids:0,
        creditScore:680,
        sponsors:[], pendingExpenses:[],
        deathCause:null,
      };
    }
    function freshInv() {
      return {
        properties:[], stocks:{}, crypto:{}, vehicles:[], businesses:[],
        k401:0, ira:0, roth:0, climate:'normal',
      };
    }

    function simOne(job) {
      GS.char = freshChar();
      GS.inv = freshInv();
      GS.nwHistory = [];
      GS.inbox = [];
      GS.billAccum = [];
      GS.pendingEvents = [];
      applyForJob(GS.char, job);
      // Track outcomes
      let retiredAt = null;
      let propsBought = 0;
      let hustlesTaken = 0;
      let peakSalary = GS.char.salary;
      let peakNW = 0;
      const cap = 90 * 12;
      while (GS.char.alive && GS.char.monthAge < cap) {
        try { monthlyTick(); } catch (e) { /* ignore */ break; }
        peakSalary = Math.max(peakSalary, GS.char.salary || 0);
