  c.checking = 5000; c.savings = 0; c.highYield = 0; c.debt = 0;
  c.employed = false; c.retired = false; c.inSchool = false;
  c.bossMorale = 65; c.performance = 70;
  c.sponsors = []; c.pendingExpenses = [];
